import React from 'react';
import { View, Text } from 'react-native';

const API_URL = 'https://api.example.com';

async function authenticate(username, password) {
  const response = await fetch(`${API_URL}/auth`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ username, password }),
  });

  if (!response.ok) {
    throw new Error('Authentication failed');
  }

  return response.json();
}

async function getUserProfile(token) {
  const response = await fetch(`${API_URL}/profile`, {
    headers: {
      'Authorization': `Bearer ${token}`,
    },
  });

  if (!response.ok) {
    throw new Error('Failed to fetch user profile');
  }

  return response.json();
}

async function updateUserData(token, data) {
  const response = await fetch(`${API_URL}/profile`, {
    method: 'PUT',
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(data),
  });

  if (!response.ok) {
    throw new Error('Failed to update user data');
  }

  return response.json();
}

export default function App() {
  const [userProfile, setUserProfile] = React.useState(null);
  const [authToken, setAuthToken] = React.useState(null);

  React.useEffect(() => {
    (async () => {
      try {
        const token = await authenticate('username', 'password');
        setAuthToken(token.token);

        const profile = await getUserProfile(token.token);
        setUserProfile(profile);
      } catch (error) {
        console.error(error);
      }
    })();
  }, []);

  const handleUpdateProfile = async (newData) => {
    try {
      const updatedProfile = await updateUserData(authToken, newData);
      setUserProfile(updatedProfile);
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <View>
      {userProfile ? (
        <>
          <Text>User Name: {userProfile.name}</Text>
          <Text>Email: {userProfile.email}</Text>
          <button onPress={() => handleUpdateProfile({ name: 'New Name' })}>Update Profile</button>
        </>
      ) : (
        <Text>Loading...</Text>
      )}
    </View>
  );
}